// ---------------------------------------------------------------------------
// Quick stats (computed once at import)
// ---------------------------------------------------------------------------
export const EXTENDED_DB_STATS = {
  totalFacilities: SA_FACILITIES_EXTENDED.length,
  generated: "2026-03-24",
  sources: 12,
  get byType() {
    const c: Record<string, number> = {};
    for (const f of SA_FACILITIES_EXTENDED) c[f.type] = (c[f.type] || 0) + 1;
    return c;
  },
  get byProvince() {
    const c: Record<string, number> = {};
    for (const f of SA_FACILITIES_EXTENDED) c[f.province] = (c[f.province] || 0) + 1;
    return c;
  },
  get withCoordinates() {
    return SA_FACILITIES_EXTENDED.filter(f => f.latitude != null).length;
  },
  get withBeds() {
    return SA_FACILITIES_EXTENDED.filter(f => f.beds != null && f.beds > 0).length;
  },
};

// ---------------------------------------------------------------------------
// Extended search — searches across ALL 6,600+ facilities
// ---------------------------------------------------------------------------

export function searchExtendedFacilities(query: string): ExtendedFacilityRecord[] {
  const lower = query.toLowerCase();
  return SA_FACILITIES_EXTENDED.filter(
    (f) =>
      f.name.toLowerCase().includes(lower) ||
      f.city.toLowerCase().includes(lower) ||
      (f.address?.toLowerCase().includes(lower) ?? false)
  );
}

export function findExtendedByProvince(province: string): ExtendedFacilityRecord[] {
  return SA_FACILITIES_EXTENDED.filter((f) => f.province === province.toUpperCase());
}

export function findExtendedByType(type: FacilityRecord["type"]): ExtendedFacilityRecord[] {
  return SA_FACILITIES_EXTENDED.filter((f) => f.type === type);
}

/** Find nearest N facilities from extended DB (uses haversine). */
export function findNearestExtended(
  lat: number,
  lng: number,
  count = 5,
  options?: { type?: FacilityRecord["type"]; maxDistanceKm?: number }
): Array<ExtendedFacilityRecord & { distanceKm: number }> {
  const R = 6371;
  const results: Array<ExtendedFacilityRecord & { distanceKm: number }> = [];

  for (const f of SA_FACILITIES_EXTENDED) {
    if (options?.type && f.type !== options.type) continue;
    if (f.latitude == null || f.longitude == null) continue;
    const dLat = ((f.latitude - lat) * Math.PI) / 180;
    const dLon = ((f.longitude - lng) * Math.PI) / 180;
    const a =
      Math.sin(dLat / 2) ** 2 +
      Math.cos((lat * Math.PI) / 180) *
        Math.cos((f.latitude * Math.PI) / 180) *
        Math.sin(dLon / 2) ** 2;
    const d = R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    if (options?.maxDistanceKm && d > options.maxDistanceKm) continue;
    results.push({ ...f, distanceKm: d });
  }

  results.sort((a, b) => a.distanceKm - b.distanceKm);
  return results.slice(0, count);
}

